function EquationVisual({ a = 2, b = 3, c = 8, onChange }) {
  const [coeffA, setCoeffA] = useState(a);
  const [coeffB, setCoeffB] = useState(b);
  const [constC, setConstC] = useState(c);
  const canvasRef = useRef(null);
  const solution = (constC - coeffB) / coeffA;
  
  useEffect(() => { onChange?.({ a: coeffA, b: coeffB, c: constC }); }, [coeffA, coeffB, constC]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const centerX = canvas.width / 2;
    const centerY = canvas.height / 2;
    const scale = 40;
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    // 画天平
    ctx.strokeStyle = '#667eea';
    ctx.lineWidth = 3;
    
    // 支点
    ctx.beginPath();
    ctx.moveTo(centerX, 30);
    ctx.lineTo(centerX, canvas.height - 20);
    ctx.stroke();
    
    // 横杆
    const tilt = solution > 0 ? Math.min(solution * 5, 30) : Math.max(solution * 5, -30);
    ctx.save();
    ctx.translate(centerX, 30);
    ctx.rotate(tilt * Math.PI / 180);
    ctx.beginPath();
    ctx.moveTo(-120, 0);
    ctx.lineTo(120, 0);
    ctx.stroke();
    
    // 左边托盘 (ax)
    ctx.fillStyle = '#ff6b6b';
    ctx.fillRect(-130, 0, 40, 50);
    ctx.strokeRect(-130, 0, 40, 50);
    ctx.fillStyle = '#fff';
    ctx.font = '14px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${coeffA}x`, -110, 35);
    
    // 右边托盘 (b 和 c)
    ctx.fillStyle = '#81c784';
    ctx.fillRect(90, 0, 80, 50);
    ctx.strokeRect(90, 0, 80, 50);
    ctx.fillStyle = '#fff';
    ctx.fillText(`${coeffB}+${constC}`, 130, 35);
    
    ctx.restore();
    
    // 解方程
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 20px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${coeffA}x + ${coeffB} = ${constC}`, centerX, canvas.height - 30);
    
    ctx.font = 'bold 24px Arial';
    ctx.fillStyle = '#ffb74d';
    ctx.fillText(`x = ${solution.toFixed(2)}`, centerX, canvas.height - 5);
    
  }, [coeffA, coeffB, constC, solution]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>⚖️ 方程演示</h3></div>
      <div className="equation-display">
        <canvas ref={canvasRef} width={400} height={250} />
        <div className="formula-box">
          <strong>方程：</strong>{coeffA}x + {coeffB} = {constC}<br />
          <span className="formula-highlight">解：x = ({constC} - {coeffB}) ÷ {coeffA} = {solution.toFixed(2)}</span>
        </div>
      </div>
      <div className="controls">
        <div className="control-group"><label>x 系数: {coeffA}</label><input type="range" min="1" max="5" value={coeffA} onChange={(e) => setCoeffA(parseInt(e.target.value))} /></div>
        <div className="control-group"><label>常数项: {coeffB}</label><input type="range" min="0" max="10" value={coeffB} onChange={(e) => setCoeffB(parseInt(e.target.value))} /></div>
        <div className="control-group"><label>等号右边: {constC}</label><input type="range" min="1" max="20" value={constC} onChange={(e) => setConstC(parseInt(e.target.value))} /></div>
      </div>
    </div>
  );
}

function FractionOpsVisual({ num1 = 1, den1 = 4, num2 = 1, den2 = 4, operator = '+', onChange }) {
  const [n1, setN1] = useState(num1);
  const [d1, setD1] = useState(den1);
  const [n2, setN2] = useState(num2);
  const [d2, setD2] = useState(den2);
  const [op, setOp] = useState(operator);
  const canvasRef = useRef(null);
  
  // 计算结果
  const getResult = () => {
    const lcm = (a, b) => {
      let g = Math.max(a, b), l = Math.min(a, b);
      for (let i = 1; i <= l; i++) {
        if (g % i === 0 && l % i === 0) {
          const gcd = i;
          return (a * b) / gcd;
        }
      }
      return a * b;
    };
    
    const commonDen = op === '+' || op === '-' ? lcm(d1, d2) : d1 * d2;
    const n1Converted = op === '+' || op === '-' ? n1 * (commonDen / d1) : n1 * d2;
    const n2Converted = op === '+' || op === '-' ? n2 * (commonDen / d2) : n2 * d1;
    const resultNum = op === '+' || op === '-' ? (op === '+' ? n1Converted + n2Converted : n1Converted - n2Converted) : n1Converted * n2Converted;
    
    return { num: resultNum, den: op === '*' ? d1 * d2 : commonDen };
  };
  
  const result = getResult();
  
  useEffect(() => { onChange?.({ num1: n1, den1: d1, num2: n2, den2: d2, operator: op }); }, [n1, d1, n2, d2, op]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    // 画第一个分数
    const drawPizza = (x, y, num, den, color) => {
      const radius = 40;
      for (let i = 0; i < den; i++) {
        const startAngle = (i * 2 * Math.PI) / den - Math.PI / 2;
        const endAngle = ((i + 1) * 2 * Math.PI) / den - Math.PI / 2;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.arc(x, y, radius, startAngle, endAngle);
        ctx.closePath();
        ctx.fillStyle = i < num ? color : 'rgba(255,255,255,0.2)';
        ctx.fill();
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 2;
        ctx.stroke();
      }
      ctx.fillStyle = '#fff';
      ctx.font = '14px Arial';
      ctx.textAlign = 'center';
      ctx.fillText(`${num}/${den}`, x, y + 60);
    };
    
    drawPizza(80, 80, n1, d1, '#ff6b6b');
    
    // 画操作符
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 30px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(op === '+' ? '+' : op === '-' ? '−' : '×', 180, 90);
    
    // 画第二个分数
    drawPizza(280, 80, n2, d2, '#81c784');
    
    // 画等号
    ctx.font = 'bold 30px Arial';
    ctx.fillText('=', 380, 90);
    
    // 画结果
    drawPizza(420, 80, result.num, result.den, '#ffb74d');
    
  }, [n1, d1, n2, d2, op, result]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>🍕 分数混合运算</h3></div>
      <div className="fraction-ops-display">
        <canvas ref={canvasRef} width={500} height={160} />
        <div className="formula-box">
          <span className="formula-highlight">{n1}/{d1} {op === '+' ? '+' : op === '-' ? '−' : '×'} {n2}/{d2} = {result.num}/{result.den}</span>
        </div>
      </div>
      <div className="controls">
        <div className="control-group"><label>第一个分子: {n1}</label><input type="range" min="1" max="9" value={n1} onChange={(e) => setN1(parseInt(e.target.value))} /></div>
        <div className="control-group"><label>第一个分母: {d1}</label><input type="range" min="2" max="12" value={d1} onChange={(e) => setD1(parseInt(e.target.value))} /></div>
        <div className="control-group"><label>运算符: {op}</label>
          <select value={op} onChange={(e) => setOp(e.target.value)}>
            <option value="+">+</option>
            <option value="-">-</option>
            <option value="*">×</option>
          </select>
        </div>
        <div className="control-group"><label>第二个分子: {n2}</label><input type="range" min="1" max="9" value={n2} onChange={(e) => setN2(parseInt(e.target.value))} /></div>
        <div className="control-group"><label>第二个分母: {d2}</label><input type="range" min="2" max="12" value={d2} onChange={(e) => setD2(parseInt(e.target.value))} /></div>
      </div>
    </div>
  );
}

function DecimalFractionVisual({ decimal = 0.75, onChange }) {
  const [dec, setDec] = useState(decimal);
  const canvasRef = useRef(null);
  
  // 转换为分数
  const decimalToFraction = (d) => {
    if (d === 0) return { num: 0, den: 1 };
    let precision = 1000;
    for (let den = 1; den <= precision; den++) {
      const num = Math.round(d * den);
      if (Math.abs(num / den - d) < 0.0001) {
        // 简化
        for (let i = 2; i <= Math.min(num, den); i++) {
          while (num % i === 0 && den % i === 0) {
            num /= i;
            den /= i;
          }
        }
        return { num, den };
      }
    }
    return { num: Math.round(d * precision), den: precision };
  };
  
  const fraction = decimalToFraction(dec);
  const percent = Math.round(dec * 100);
  
  useEffect(() => { onChange?.({ decimal: dec }); }, [dec]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const centerX = canvas.width / 2, centerY = canvas.height / 2;
    const radius = Math.min(centerX, centerY) - 20;
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    // 画饼图
    const filledParts = Math.round(dec * 100) / (100 / 100);
    const slices = 100;
    
    for (let i = 0; i < slices; i++) {
      const startAngle = (i * 2 * Math.PI) / slices - Math.PI / 2;
      const endAngle = ((i + 1) * 2 * Math.PI) / slices - Math.PI / 2;
      ctx.beginPath();
      ctx.moveTo(centerX, centerY);
      ctx.arc(centerX, centerY, radius, startAngle, endAngle);
      ctx.closePath();
      ctx.fillStyle = i < dec * 100 ? '#667eea' : 'rgba(255,255,255,0.1)';
      ctx.fill();
    }
    
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 24px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(`${percent}%`, centerX, centerY);
    
  }, [dec, percent]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>🔄 小数与分数互化</h3></div>
      <div className="decimal-fraction-display">
        <canvas ref={canvasRef} width={200} height={200} />
        <div className="fraction-equation">
          <div className="big-fraction">
            <span className="numerator">{fraction.num}</span>
            <div className="fraction-line"></div>
            <span className="denominator">{fraction.den}</span>
          </div>
          <div className="percent-badge">= {dec.toFixed(2)}</div>
        </div>
      </div>
      <div className="controls">
        <div className="control-group"><label>小数: {dec.toFixed(2)}</label><input type="range" min="0" max="100" value={dec * 100} onChange={(e) => setDec(parseInt(e.target.value) / 100)} /></div>
      </div>
    </div>
  );
}

function CirclePiVisual({ radius = 5, onChange }) {
  const [r, setR] = useState(radius);
  const canvasRef = useRef(null);
  const circumference = 2 * Math.PI * r;
  const area = Math.PI * r * r;
  
  useEffect(() => { onChange?.({ radius: r }); }, [r]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const centerX = canvas.width / 2;
    const centerY = canvas.height / 2;
    const scale = Math.min(centerX, centerY) - 40;
    const displayR = Math.min(r * 8, scale);
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    // 画圆
    ctx.beginPath();
    ctx.arc(centerX, centerY, displayR, 0, 2 * Math.PI);
    ctx.fillStyle = 'rgba(102, 126, 234, 0.3)';
    ctx.fill();
    ctx.strokeStyle = '#667eea';
    ctx.lineWidth = 3;
    ctx.stroke();
    
    // 画直径
    ctx.beginPath();
    ctx.moveTo(centerX - displayR, centerY);
    ctx.lineTo(centerX + displayR, centerY);
    ctx.strokeStyle = '#ff6b6b';
    ctx.lineWidth = 3;
    ctx.stroke();
    
    // 画半径
    ctx.beginPath();
    ctx.moveTo(centerX, centerY);
    ctx.lineTo(centerX + displayR, centerY);
    ctx.strokeStyle = '#81c784';
    ctx.lineWidth = 3;
    ctx.stroke();
    
    // 标注
    ctx.fillStyle = '#fff';
    ctx.font = '14px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`r = ${r}`, centerX + displayR / 2, centerY - 15);
    ctx.fillText(`d = ${r * 2}`, centerX, centerY + 20);
    ctx.fillText(`π ≈ 3.14159`, centerX, centerY - displayR - 20);
    
  }, [r]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>⭕ 圆和圆周率</h3></div>
      <div className="circle-display">
        <canvas ref={canvasRef} width={300} height={250} />
        <div className="formula-box">
          <strong>公式：</strong><br />
          周长 = 2 × π × r = 2π × {r} ≈ {circumference.toFixed(2)}<br />
          面积 = π × r² = π × {r}² ≈ {area.toFixed(2)}
        </div>
      </div>
      <div className="controls">
        <div className="control-group"><label>半径: {r}</label><input type="range" min="1" max="10" value={r} onChange={(e) => setR(parseInt(e.target.value))} /></div>
      </div>
    </div>
  );
}

