function CuboidVisual({ length = 6, width = 4, height = 3, onChange }) {
  const [l, setL] = useState(length);
  const [w, setW] = useState(width);
  const [h, setH] = useState(height);
  const canvasRef = useRef(null);
  const surfaceArea = 2 * (l * w + w * h + l * h);
  const volume = l * w * h;
  
  useEffect(() => { onChange?.({ length: l, width: w, height: h }); }, [l, w, h]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    const scale = 20;
    const offsetX = 50, offsetY = 50;
    
    // 顶面 (平行四边形)
    ctx.beginPath();
    ctx.moveTo(offsetX, offsetY);
    ctx.lineTo(offsetX + l * scale, offsetY - l * scale * 0.3);
    ctx.lineTo(offsetX + l * scale + w * scale * 0.5, offsetY - l * scale * 0.3 + w * scale);
    ctx.lineTo(offsetX + w * scale * 0.5, offsetY + w * scale);
    ctx.closePath();
    ctx.fillStyle = 'rgba(102, 126, 234, 0.5)';
    ctx.fill();
    ctx.strokeStyle = '#667eea';
    ctx.lineWidth = 2;
    ctx.stroke();
    
    // 左面
    ctx.beginPath();
    ctx.moveTo(offsetX, offsetY);
    ctx.lineTo(offsetX + w * scale * 0.5, offsetY + w * scale);
    ctx.lineTo(offsetX + w * scale * 0.5 + l * scale, offsetY + w * scale - l * scale * 0.3);
    ctx.lineTo(offsetX + l * scale, offsetY - l * scale * 0.3);
    ctx.closePath();
    ctx.fillStyle = 'rgba(129, 199, 132, 0.5)';
    ctx.fill();
    ctx.stroke();
    
    // 前面
    ctx.beginPath();
    ctx.moveTo(offsetX + w * scale * 0.5, offsetY + w * scale);
    ctx.lineTo(offsetX + w * scale * 0.5 + l * scale, offsetY + w * scale - l * scale * 0.3);
    ctx.lineTo(offsetX + w * scale * 0.5 + l * scale, offsetY + w * scale + h * scale - l * scale * 0.3);
    ctx.lineTo(offsetX + w * scale * 0.5, offsetY + w * scale + h * scale);
    ctx.closePath();
    ctx.fillStyle = 'rgba(245, 87, 108, 0.5)';
    ctx.fill();
    ctx.stroke();
    
    // 标注
    ctx.fillStyle = '#fff';
    ctx.font = '12px Arial';
    ctx.fillText(`长=${l}`, offsetX + l * scale / 2 + 30, offsetY - l * scale * 0.3 - 10);
    ctx.fillText(`宽=${w}`, offsetX + w * scale * 0.5 / 2, offsetY + w * scale / 2);
    ctx.fillText(`高=${h}`, offsetX + 10, offsetY + w * scale / 2 + h * scale / 2);
    
  }, [l, w, h]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>📦 长方体与正方体</h3></div>
      <div className="cuboid-display">
        <canvas ref={canvasRef} width={400} height={250} />
        <div className="formula-box">
          <strong>公式：</strong><br />
          表面积 = 2×(长×宽+宽×高+长×高) = {surfaceArea}<br />
          体积 = 长 × 宽 × 高 = {volume}
        </div>
      </div>
      <div className="controls">
        <div className="control-group"><label>长度: {l}</label><input type="range" min="1" max="10" value={l} onChange={(e) => setL(parseInt(e.target.value))} /></div>
        <div className="control-group"><label>宽度: {w}</label><input type="range" min="1" max="10" value={w} onChange={(e) => setW(parseInt(e.target.value))} /></div>
        <div className="control-group"><label>高度: {h}</label><input type="range" min="1" max="10" value={h} onChange={(e) => setH(parseInt(e.target.value))} /></div>
      </div>
    </div>
  );
}

function ScalingVisual({ scale = 2, onChange }) {
  const [s, setS] = useState(scale);
  const canvasRef = useRef(null);
  
  useEffect(() => { onChange?.({ scale: s }); }, [s]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    const baseSize = 50;
    const offsetX = 80;
    const offsetY = 100;
    
    // 原图形
    ctx.fillStyle = 'rgba(102, 126, 234, 0.5)';
    ctx.fillRect(offsetX, offsetY, baseSize, baseSize);
    ctx.strokeStyle = '#667eea';
    ctx.lineWidth = 2;
    ctx.strokeRect(offsetX, offsetY, baseSize, baseSize);
    
    // 放大后的图形
    const scaledSize = baseSize * s;
    ctx.fillStyle = 'rgba(245, 87, 108, 0.5)';
    ctx.fillRect(offsetX + scaledSize + 30, offsetY, scaledSize, scaledSize);
    ctx.strokeStyle = '#f5576c';
    ctx.strokeRect(offsetX + scaledSize + 30, offsetY, scaledSize, scaledSize);
    
    // 箭头
    ctx.beginPath();
    ctx.moveTo(offsetX + baseSize + 10, offsetY + baseSize / 2);
    ctx.lineTo(offsetX + scaledSize + 20, offsetY + baseSize / 2);
    ctx.strokeStyle = '#81c784';
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(offsetX + scaledSize + 20, offsetY + baseSize / 2 - 8);
    ctx.lineTo(offsetX + scaledSize + 30, offsetY + baseSize / 2);
    ctx.lineTo(offsetX + scaledSize + 20, offsetY + baseSize / 2 + 8);
    ctx.stroke();
    
    // 标注
    ctx.fillStyle = '#fff';
    ctx.font = '14px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`原图形`, offsetX + baseSize / 2, offsetY + baseSize + 25);
    ctx.fillText(`边长=${baseSize}`, offsetX + baseSize / 2, offsetY + baseSize + 40);
    ctx.fillText(`面积=${baseSize * baseSize}`, offsetX + baseSize / 2, offsetY + baseSize + 55);
    
    ctx.fillStyle = '#ffb74d';
    ctx.fillText(`放大 ${s} 倍`, offsetX + scaledSize + 30 + scaledSize / 2, offsetY + scaledSize + 25);
    ctx.fillText(`边长=${scaledSize}`, offsetX + scaledSize + 30 + scaledSize / 2, offsetY + scaledSize + 40);
    ctx.fillText(`面积=${scaledSize * scaledSize}`, offsetX + scaledSize + 30 + scaledSize / 2, offsetY + scaledSize + 55);
    
  }, [s]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>🔍 图形缩放</h3></div>
      <div className="scaling-display">
        <canvas ref={canvasRef} width={450} height={200} />
        <div className="formula-box">
          <strong>规律：</strong>放大 n 倍，面积变成 n² 倍<br />
          <span className="formula-highlight">边长 1 → {s}，面积 1 → {s * s}</span>
        </div>
      </div>
      <div className="controls">
        <div className="control-group"><label>放大倍数: {s}倍</label><input type="range" min="1" max="5" value={s} onChange={(e) => setS(parseInt(e.target.value))} /></div>
      </div>
    </div>
  );
}

function AverageVisual({ values = [85, 92, 78, 96, 88], onChange }) {
  const [vals, setVals] = useState(values);
  const canvasRef = useRef(null);
  const avg = vals.reduce((a, b) => a + b, 0) / vals.length;
  
  useEffect(() => { onChange?.({ values: vals }); }, [vals]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const barWidth = 50;
    const gap = 20;
    const offsetX = 50;
    const offsetY = 150;
    const maxHeight = 120;
    const maxVal = 100;
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    // 画平均线
    const avgY = offsetY + maxHeight - (avg / maxVal) * maxHeight;
    ctx.beginPath();
    ctx.setLineDash([5, 5]);
    ctx.moveTo(0, avgY);
    ctx.lineTo(canvas.width, avgY);
    ctx.strokeStyle = '#ffb74d';
    ctx.lineWidth = 3;
    ctx.stroke();
    ctx.setLineDash([]);
    
    ctx.fillStyle = '#ffb74d';
    ctx.font = '12px Arial';
    ctx.textAlign = 'left';
    ctx.fillText(`平均=${avg.toFixed(1)}`, 10, avgY - 5);
    
    // 画柱状图
    vals.forEach((v, i) => {
      const x = offsetX + i * (barWidth + gap);
      const barHeight = (v / maxVal) * maxHeight;
      
      ctx.fillStyle = i === vals.indexOf(Math.max(...vals)) ? '#81c784' : 
                      i === vals.indexOf(Math.min(...vals)) ? '#ff6b6b' : '#667eea';
      ctx.fillRect(x, offsetY + maxHeight - barHeight, barWidth, barHeight);
      
      ctx.fillStyle = '#fff';
      ctx.font = '12px Arial';
      ctx.textAlign = 'center';
      ctx.fillText(v.toString(), x + barWidth / 2, offsetY + maxHeight - barHeight - 5);
      ctx.fillText(`第${i + 1}次`, x + barWidth / 2, offsetY + maxHeight + 15);
    });
    
    // 画基础线
    ctx.strokeStyle = 'rgba(255,255,255,0.3)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(0, offsetY);
    ctx.lineTo(canvas.width, offsetY);
    ctx.moveTo(0, offsetY + maxHeight);
    ctx.lineTo(canvas.width, offsetY + maxHeight);
    ctx.stroke();
    
  }, [vals, avg]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>📊 平均数</h3></div>
      <div className="average-display">
        <canvas ref={canvasRef} width={400} height={200} />
        <div className="formula-box">
          <strong>平均数公式：</strong>(数据之和) ÷ (数据个数)<br />
          <span className="formula-highlight">= (${vals.join('+')}) ÷ ${vals.length} = ${avg.toFixed(2)}</span>
        </div>
      </div>
      <div className="controls">
        {vals.map((v, i) => (
          <div key={i} className="control-group">
            <label>第{i + 1}个数: {v}</label>
            <input type="range" min="0" max="100" value={v} onChange={(e) => {
              const newVals = [...vals];
              newVals[i] = parseInt(e.target.value);
              setVals(newVals);
            }} />
          </div>
        ))}
      </div>
    </div>
  );
}

function MedianModeVisual({ values = [85, 92, 78, 92, 88], onChange }) {
  const [vals, setVals] = useState(values);
  const canvasRef = useRef(null);
  
  const getStats = () => {
    const sorted = [...vals].sort((a, b) => a - b);
    const median = sorted.length % 2 === 0 
      ? (sorted[sorted.length / 2 - 1] + sorted[sorted.length / 2]) / 2
      : sorted[Math.floor(sorted.length / 2)];
    
    const counts = {};
    vals.forEach(v => counts[v] = (counts[v] || 0) + 1);
    const maxCount = Math.max(...Object.values(counts));
    const modes = Object.keys(counts).filter(k => counts[k] === maxCount).map(Number);
    
    return { median, modes, counts };
  };
  
  const { median, modes, counts } = getStats();
  
  useEffect(() => { onChange?.({ values: vals }); }, [vals]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    const sorted = [...new Set(vals)].sort((a, b) => a - b);
    const dotRadius = 20;
    const spacing = 50;
    const startX = 50;
    const y = 100;
    
    sorted.forEach((v, i) => {
      const x = startX + i * spacing;
      const count = counts[v];
      const isMedian = v === median || (Array.isArray(median) && median.includes(v));
      const isMode = modes.includes(v);
      
      // 画数据点
      ctx.beginPath();
      ctx.arc(x, y, dotRadius * Math.sqrt(count), 0, 2 * Math.PI);
      ctx.fillStyle = isMode ? '#ffb74d' : isMedian ? '#667eea' : '#81c784';
      ctx.globalAlpha = 0.7;
      ctx.fill();
      ctx.globalAlpha = 1;
      ctx.strokeStyle = '#fff';
      ctx.lineWidth = 2;
      ctx.stroke();
      
      // 标注
      ctx.fillStyle = '#fff';
      ctx.font = 'bold 14px Arial';
      ctx.textAlign = 'center';
      ctx.fillText(v.toString(), x, y + 5);
      ctx.font = '12px Arial';
      ctx.fillText(`×${count}`, x, y + 25);
    });
    
    // 图例
    ctx.fillStyle = '#667eea';
    ctx.fillRect(50, 180, 15, 15);
    ctx.fillStyle = '#fff';
    ctx.font = '12px Arial';
    ctx.textAlign = 'left';
    ctx.fillText('中位数', 70, 192);
    
    ctx.fillStyle = '#ffb74d';
    ctx.fillRect(130, 180, 15, 15);
    ctx.fillStyle = '#fff';
    ctx.fillText('众数', 150, 192);
    
  }, [vals, median, modes, counts]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>📈 中位数与众数</h3></div>
      <div className="median-mode-display">
        <canvas ref={canvasRef} width={350} height={220} />
        <div className="formula-box">
          <strong>中位数：</strong>排序后中间的值 = {Array.isArray(median) ? median.join(', ') : median}<br />
          <strong>众数：</strong>出现最多的数 = {modes.join(', ')}
        </div>
      </div>
      <div className="controls">
        {vals.map((v, i) => (
          <div key={i} className="control-group">
            <label>第{i + 1}个数: {v}</label>
            <input type="range" min="0" max="100" value={v} onChange={(e) => {
              const newVals = [...vals];
              newVals[i] = parseInt(e.target.value);
              setVals(newVals);
            }} />
          </div>
        ))}
      </div>
    </div>
  );
}

function ProbabilityVisual({ favorable = 3, total = 8, onChange }) {
  const [fav, setFav] = useState(favorable);
  const [tot, setTot] = useState(total);
  const canvasRef = useRef(null);
  
  const probability = tot > 0 ? fav / tot : 0;
  const percent = Math.round(probability * 100);
  
  useEffect(() => { onChange?.({ favorable: fav, total: tot }); }, [fav, tot]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const centerX = canvas.width / 2;
    const centerY = canvas.height / 2;
    const radius = Math.min(centerX, centerY) - 30;
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    // 画所有可能（灰色背景球）
    for (let i = 0; i < tot; i++) {
      const angle = (i * 2 * Math.PI) / tot - Math.PI / 2;
      const x = centerX + Math.cos(angle) * radius * 0.7;
      const y = centerY + Math.sin(angle) * radius * 0.7;
      
      ctx.beginPath();
      ctx.arc(x, y, 20, 0, 2 * Math.PI);
      ctx.fillStyle = 'rgba(255,255,255,0.2)';
      ctx.fill();
      ctx.strokeStyle = 'rgba(255,255,255,0.5)';
      ctx.lineWidth = 2;
      ctx.stroke();
    }
    
    // 画符合条件的（彩色球）
    for (let i = 0; i < fav; i++) {
      const angle = (i * 2 * Math.PI) / tot - Math.PI / 2;
      const x = centerX + Math.cos(angle) * radius;
      const y = centerY + Math.sin(angle) * radius;
      
      ctx.beginPath();
      ctx.arc(x, y, 20, 0, 2 * Math.PI);
      ctx.fillStyle = '#ff6b6b';
      ctx.fill();
      ctx.strokeStyle = '#fff';
      ctx.lineWidth = 2;
      ctx.stroke();
    }
    
    // 中心文字
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 24px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(`${percent}%`, centerX, centerY);
    
    // 图例
    ctx.font = '14px Arial';
    ctx.fillStyle = '#ff6b6b';
    ctx.fillRect(50, 220, 15, 15);
    ctx.fillStyle = '#fff';
    ctx.textAlign = 'left';
    ctx.fillText(`符合条件: ${fav} 个`, 70, 232);
    
    ctx.fillStyle = 'rgba(255,255,255,0.3)';
    ctx.fillRect(50, 240, 15, 15);
    ctx.fillStyle = '#fff';
    ctx.fillText(`不符合: ${tot - fav} 个`, 70, 252);
    
  }, [fav, tot, percent]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>🎲 可能性与概率</h3></div>
      <div className="probability-display">
        <canvas ref={canvasRef} width={300} height={280} />
        <div className="formula-box">
          <strong>概率公式：</strong>符合条件数 ÷ 总数<br />
          <span className="formula-highlight">P = {fav} ÷ {tot} = {probability.toFixed(3)} = {percent}%</span>
        </div>
      </div>
      <div className="controls">
        <div className="control-group"><label>符合条件数: {fav}</label><input type="range" min="0" max={tot} value={fav} onChange={(e) => setFav(parseInt(e.target.value))} /></div>
        <div className="control-group"><label>总数: {tot}</label><input type="range" min="1" max="20" value={tot} onChange={(e) => { setTot(parseInt(e.target.value)); if (fav > parseInt(e.target.value)) setFav(parseInt(e.target.value)); }} /></div>
      </div>
    </div>
  );
}

function ExpressionPlotter({ onChange }) {
  const [yExpression, setYExpression] = useState("x^2");
  const [error, setError] = useState(null);
  const canvasRef = useRef(null);
  
  const parseExpression = useCallback((expr) => {
    try {
      const normalizedExpr = expr.replace(/\^/g, '**');
      const fn = math.compile(normalizedExpr);
      return (x) => {
        try { return fn.evaluate({ x: x }); } catch { return NaN; }
      };
    } catch (e) {
      setError("表达式解析错误: " + e.message);
      return null;
    }
  }, []);
  
  const presetExpressions = [
    { label: "二次函数", expr: "x^2" },
    { label: "一次函数", expr: "2*x + 1" },
    { label: "反比例", expr: "1/x" },
    { label: "三次函数", expr: "x^3" },
    { label: "正弦波", expr: "sin(x)" },
    { label: "余弦波", expr: "cos(x)" },
  ];
  
  useEffect(() => { onChange?.({ expression: yExpression }); }, [yExpression]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const fn = parseExpression(yExpression);
    if (!fn) return;
    setError(null);
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    const centerX = canvas.width / 2;
    const centerY = canvas.height / 2;
    const scale = 20;
    
    ctx.strokeStyle = 'rgba(255,255,255,0.3)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(0, centerY);
    ctx.lineTo(canvas.width, centerY);
    ctx.moveTo(centerX, 0);
    ctx.lineTo(centerX, canvas.height);
    ctx.stroke();
    
    ctx.beginPath();
    ctx.strokeStyle = '#667eea';
    ctx.lineWidth = 2;
    
    let started = false;
    for (let px = 0; px < canvas.width; px++) {
      const x = (px - centerX) / scale;
      const y = fn(x);
      if (isNaN(y) || !isFinite(y) || y < -500 || y > 500) { started = false; continue; }
      const py = centerY - y * scale;
      if (!started) { ctx.moveTo(px, py); started = true; } else ctx.lineTo(px, py);
    }
    ctx.stroke();
  }, [yExpression, parseExpression]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>📈 表达式绘图器</h3><p className="subtitle">输入任意数学表达式，实时生成交互式图表</p></div>
      <div className="expression-input-section">
        <div className="input-group">
          <label>📝 输入数学表达式（用 x 作为变量）：</label>
          <input type="text" value={yExpression} onChange={(e) => setYExpression(e.target.value)} placeholder="例如: sin(x), x^2 + 2*x - 1" className="expression-input" />
        </div>
        {error && <div className="error-msg">{error}</div>}
        <div className="preset-expressions">
          <span className="preset-label">快速选择：</span>
          <div className="preset-btns">
            {presetExpressions.map((preset, i) => (
              <button key={i} className="preset-btn" onClick={() => setYExpression(preset.expr)}>{preset.label}</button>
            ))}
          </div>
        </div>
      </div>
      <canvas ref={canvasRef} width={400} height={250} />
      <div className="formula-box"><strong>当前表达式：</strong> y = {yExpression}<br /><span className="help-text">支持: + - * / ^ sqrt() sin() cos() tan() abs()</span></div>
    </div>
  );
}

function FunctionVisual({ fnType = 'linear', onChange }) {
  const [slope, setSlope] = useState(2);
  const [intercept, setIntercept] = useState(1);
  const canvasRef = useRef(null);
  
  useEffect(() => { onChange?.({ slope, intercept }); }, [slope, intercept]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const centerX = canvas.width / 2;
    const centerY = canvas.height / 2;
    const scale = 25;
    
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    ctx.strokeStyle = 'rgba(255,255,255,0.3)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(0, centerY);
    ctx.lineTo(canvas.width, centerY);
    ctx.moveTo(centerX, 0);
    ctx.lineTo(centerX, canvas.height);
    ctx.stroke();
    
    ctx.beginPath();
    ctx.strokeStyle = '#667eea';
    ctx.lineWidth = 2;
    
    let started = false;
    for (let px = 0; px < canvas.width; px++) {
      const x = (px - centerX) / scale;
      const y = slope * x + intercept;
      const py = centerY - y * scale;
      if (!started) { ctx.moveTo(px, py); started = true; } else ctx.lineTo(px, py);
    }
    ctx.stroke();
  }, [slope, intercept]);
  
  return (
    <div className="visual-container">
      <div className="visual-header"><h3>📈 {fnType === 'linear' ? '一次函数' : '二次函数'}</h3></div>
      <canvas ref={canvasRef} width={350} height={300} />
      <div className="formula-box"><strong>函数公式：</strong>y = {slope}x + {intercept}</div>
      <div className="controls">
        <div className="control-group"><label>斜率: {slope}</label><input type="range" min="-5" max="5" value={slope} onChange={(e) => setSlope(parseInt(e.target.value))} /></div>
        <div className="control-group"><label>截距: {intercept}</label><input type="range" min="-5" max="5" value={intercept} onChange={(e) => setIntercept(parseInt(e.target.value))} /></div>
      </div>
    </div>
  );
}

