// ========================================
// 🎯 动态可视化选择器
// ========================================

function DynamicVisualization({ config, onParamsChange }) {
  const { visualization, params = {} } = config;
  
  switch (visualization) {
    case 'fraction': return <FractionVisual {...params} onChange={onParamsChange} />;
    case 'pythagorean': return <PythagoreanVisual {...params} onChange={onParamsChange} />;
    case 'percentage': return <PercentageVisual {...params} onChange={onParamsChange} />;
    case 'positive-negative': return <PositiveNegativeVisual {...params} onChange={onParamsChange} />;
    case 'triangle-area': return <TriangleAreaVisual {...params} onChange={onParamsChange} />;
    case 'rectangle-area': return <RectangleAreaVisual {...params} onChange={onParamsChange} />;
    case 'multiplication': return <MultiplicationVisual {...params} onChange={onParamsChange} />;
    case 'bar-chart': return <BarChartVisual {...params} onChange={onParamsChange} />;
    case 'expression':
    case 'plotter': return <ExpressionPlotter {...params} onChange={onParamsChange} />;
    case 'function':
    case 'line': return <FunctionVisual {...params} onChange={onParamsChange} />;
    // 新增的可视化类型
    case 'equation': return <EquationVisual {...params} onChange={onParamsChange} />;
    case 'fraction-ops': return <FractionOpsVisual {...params} onChange={onParamsChange} />;
    case 'decimal-fraction': return <DecimalFractionVisual {...params} onChange={onParamsChange} />;
    case 'circle-pi': return <CirclePiVisual {...params} onChange={onParamsChange} />;
    case 'cylinder': return <CylinderVisual {...params} onChange={onParamsChange} />;
    case 'cone': return <ConeVisual {...params} onChange={onParamsChange} />;
    case 'cuboid': return <CuboidVisual {...params} onChange={onParamsChange} />;
    case 'scaling': return <ScalingVisual {...params} onChange={onParamsChange} />;
    case 'average': return <AverageVisual {...params} onChange={onParamsChange} />;
    case 'median-mode': return <MedianModeVisual {...params} onChange={onParamsChange} />;
    case 'probability': return <ProbabilityVisual {...params} onChange={onParamsChange} />;
    default: return <FunctionVisual {...params} onChange={onParamsChange} />;
  }
}

// ========================================
// 主应用
// ========================================

function App() {
  const [input, setInput] = useState("");
  const [currentConfig, setCurrentConfig] = useState(null);
  const [showDemo, setShowDemo] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [language, setLanguage] = useState('zh');
  const [stars, setStars] = useState(0);
  const [achievedIds, setAchievedIds] = useState([]);
  const [newAchievement, setNewAchievement] = useState(null);
  const [viewedConcepts, setViewedConcepts] = useState(new Set());
  
  const checkAchievements = useCallback((conceptId) => {
    const newViewed = new Set(viewedConcepts);
    newViewed.add(conceptId);
    setViewedConcepts(newViewed);
    ACHIEVEMENTS.forEach(achievement => {
      if (!achievedIds.includes(achievement.id)) {
        if (achievement.id === 'first_look' && newViewed.size >= 1) {
          setAchievedIds(p => [...p, achievement.id]);
          setStars(s => s + 10);
          setNewAchievement(achievement);
          setTimeout(() => setNewAchievement(null), 3000);
        } else if (achievement.id === 'curious_mind' && newViewed.size >= 3) {
          setAchievedIds(p => [...p, achievement.id]);
          setStars(s => s + 10);
          setNewAchievement(achievement);
          setTimeout(() => setNewAchievement(null), 3000);
        } else if (achievement.id === 'math_explorer' && newViewed.size >= 8) {
          setAchievedIds(p => [...p, achievement.id]);
          setStars(s => s + 10);
          setNewAchievement(achievement);
          setTimeout(() => setNewAchievement(null), 3000);
        }
      }
    });
  }, [achievedIds, viewedConcepts]);
  
  const analyzeConcept = useCallback(async (concept) => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch(`${API_BASE}/api/analyze`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ concept })
      });
      if (!response.ok) throw new Error('分析请求失败');
      const data = await response.json();
      const config = {
        visualization: data.visualization || 'expression',
        title: data.title || concept,
        params: data.params || {},
        explanation: { title: data.title || concept, concept: data.explanation || concept, points: data.points || [], tips: data.tips || '', example: data.example || '' },
        gradeLevel: data.gradeLevel
      };
      setCurrentConfig(config);
      setShowDemo(true);
      checkAchievements(concept);
    } catch (err) {
      console.error('AI分析失败，使用本地知识库:', err);
      const matchedKey = Object.keys(EXPLANATIONS).find(key => concept.includes(key.toLowerCase()) || key.includes(concept));
      const explanation = matchedKey ? EXPLANATIONS[matchedKey] : null;
      const config = {
        visualization: matchedKey || 'expression',
        title: explanation?.title || concept,
        params: {},
        explanation: explanation || { title: concept, concept: `关于"${concept}"的数学知识`, points: ['这是一个数学概念'], tips: '尝试调节下方的参数来探索这个概念', example: '' }
      };
      setCurrentConfig(config);
      setShowDemo(true);
      setError('使用本地知识库，您也可以直接输入任意数学表达式探索');
      checkAchievements(matchedKey || concept);
    } finally {
      setLoading(false);
    }
  }, [checkAchievements]);
  
  const handleSearch = () => { if (!input.trim()) return; analyzeConcept(input); };
  const handleKeyPress = (e) => { if (e.key === "Enter") handleSearch(); };
  
  const handleParamsChange = (newParams) => {
    setCurrentConfig(prev => { if (!prev) return null; return { ...prev, params: { ...prev.params, ...newParams } }; });
  };
  
  const handleQuickClick = (item) => {
    setInput(item.label);
    const matchedKey = Object.keys(EXPLANATIONS).find(key => item.label.includes(key) || key.includes(item.label));
    const explanation = matchedKey ? EXPLANATIONS[matchedKey] : null;
    setCurrentConfig({
      visualization: item.config?.visualization || item.visualization,
      title: item.label,
      params: item.config?.params || item.params || {},
      explanation: explanation || DEFAULT_EXPLANATION
    });
    setShowDemo(true);
    setError(null);
    checkAchievements(item.label);
  };
  
  const handleBack = () => { setShowDemo(false); setCurrentConfig(null); setInput(""); };
  
  const quickConcepts = [
    { label: "分数的认识", config: { visualization: 'fraction', params: { numerator: 3, denominator: 4 } } },
    { label: "勾股定理", config: { visualization: 'pythagorean', params: { a: 3, b: 4 } } },
    { label: "三角形面积", config: { visualization: 'triangle-area', params: { base: 6, height: 4 } } },
    { label: "百分比", config: { visualization: 'percentage', params: { value: 65 } } },
    { label: "正负数", config: { visualization: 'positive-negative', params: { value: 5 } } },
    { label: "方程初步", config: { visualization: 'equation', params: { a: 2, b: 3, c: 8 } } },
    { label: "圆和圆周率", config: { visualization: 'circle-pi', params: { radius: 5 } } },
    { label: "可能性与概率", config: { visualization: 'probability', params: { favorable: 3, total: 8 } } },
  ];
  
  const t = LANGUAGES[language];
  
  return (
    <div className="app">
      {newAchievement && <AchievementPopup achievement={newAchievement} onClose={() => setNewAchievement(null)} />}
      <header className="header">
        <div className="logo"><span className="logo-icon">🧪</span><span className="logo-text">{t.title}</span></div>
        <div className="header-right">
          <div className="language-selector">
            <button className={language === 'zh' ? 'active' : ''} onClick={() => setLanguage('zh')}>中文</button>
            <button className={language === 'en' ? 'active' : ''} onClick={() => setLanguage('en')}>EN</button>
          </div>
          <div className="user-stats"><span className="stars-badge">⭐ {stars}</span></div>
        </div>
      </header>
      <main className="main-content">
        {!showDemo ? (
          <>
            <section className="hero">
              <h1 className="hero-title"><span className="gradient-text">{t.subtitle}</span></h1>
              <p className="hero-subtitle">{language === 'zh' ? '输入一个数学概念 ✨ 自动生成动画演示 + 文字讲解' : 'Enter a math concept ✨ Auto-generate animations + explanations'}</p>
              {language === 'zh' && <div className="ai-badge"><span className="ai-icon">🤖</span><span>AI 智能分析 · 多语言支持</span></div>}
            </section>
            <section className="search-section">
              <div className="search-box">
                <input type="text" value={input} onChange={(e) => setInput(e.target.value)} onKeyPress={handleKeyPress} placeholder={t.searchPlaceholder} />
                <button onClick={handleSearch}>{loading ? t.exploring : t.explore}</button>
              </div>
              {error && <div className="error-msg">{error}</div>}
            </section>
            <section className="quick-section">
              <h3 className="section-title">{t.quickExplore}</h3>
              <div className="quick-concepts">{quickConcepts.map((item, i) => <button key={i} className="quick-btn" onClick={() => handleQuickClick(item)}>{item.label}</button>)}</div>
            </section>
            <section className="knowledge-section">
              <h3 className="section-title">{t.knowledgeBase}</h3>
              {Object.entries(KNOWLEDGE_BASE).map(([grade, items]) => (
                <div key={grade} className="grade-group">
                  <h4 className="grade-title">{grade === '1-2年级' ? t.grade1_2 : grade === '3-4年级' ? t.grade3_4 : t.grade5_6}</h4>
                  <div className="grade-items">{items.map((item, i) => <button key={i} className="grade-btn" onClick={() => handleQuickClick(item)}>{item.label}</button>)}</div>
                </div>
              ))}
            </section>
            <section className="features">
              <div className="feature-card"><span className="feature-icon">🎬</span><h3>{t.features.animation.title}</h3><p>{t.features.animation.desc}</p></div>
              <div className="feature-card"><span className="feature-icon">📖</span><h3>{t.features.explanation.title}</h3><p>{t.features.explanation.desc}</p></div>
              <div className="feature-card"><span className="feature-icon">🎮</span><h3>{t.features.interactive.title}</h3><p>{t.features.interactive.desc}</p></div>
            </section>
          </>
        ) : (
          <section className="demo-page">
            <button className="back-btn" onClick={handleBack}>{t.back}</button>
            <div className="demo-title"><h2>{currentConfig?.title || t.title}</h2></div>
            <div className="demo-content"><DynamicVisualization config={{ visualization: currentConfig?.visualization, params: currentConfig?.params }} onParamsChange={handleParamsChange} /></div>
            <ExplanationCard explanation={currentConfig?.explanation} />
            <div className="explore-more">
              <h4>{t.exploreMore}</h4>
              <div className="more-concepts">{quickConcepts.filter(item => item.label !== currentConfig?.title).slice(0, 4).map((item, i) => <button key={i} className="more-btn" onClick={() => handleQuickClick(item)}>{item.label}</button>)}</div>
            </div>
          </section>
        )}
      </main>
    </div>
  );
}

export default App;
